const input = $input.first().json || {};
const projectId = String(input.projectId || '').trim();
const actor = String(input.actor || 'document-verwerker').trim();
const raw = Array.isArray(input.observations) ? input.observations : (Array.isArray(input.bronwaarden) ? input.bronwaarden : []);
if (!projectId) throw new Error('projectId is verplicht');
if (!raw.length) throw new Error('Minimaal één bronwaarde is verplicht');
const observations = raw.map((item, index) => {
  if (!item || typeof item !== 'object') throw new Error(`Bronwaarde ${index + 1} is ongeldig`);
  const field = String(item.field || '').trim();
  if (!field) throw new Error(`Bronwaarde ${index + 1}: field ontbreekt`);
  if (item.value === undefined || item.value === null || item.value === '') throw new Error(`Bronwaarde ${index + 1}: value ontbreekt`);
  if (!item.source || typeof item.source !== 'object' || !String(item.source.type || '').trim()) throw new Error(`Bronwaarde ${index + 1}: source.type ontbreekt`);
  return {
    id: item.id || undefined,
    field,
    value: item.value,
    unit: item.unit || undefined,
    observedAt: item.observedAt || new Date().toISOString(),
    source: {
      type: String(item.source.type),
      document: item.source.document || undefined,
      path: item.source.path || undefined,
      page: item.source.page || undefined,
      field: item.source.field || undefined,
      uri: item.source.uri || undefined,
      extract: item.source.extract || undefined
    }
  };
});
return [{ json: { projectId, actor, observations } }];
